sql:
SELECT chimp_id, name, health_status
FROM chimps
WHERE weight > 30.0;

SELECT COUNT(*) 
FROM chimps 
WHERE (strftime('%Y', 'now') - strftime('%Y', date_of_birth)) > 5;

external_knowledge:
"spots in the chimpanzee habitats" refers to locations where chimpanzees reside;
"impressive average score" refers to an average score greater than 75;
"how many chimps participated" refers to the count of distinct chimpanzees in each location;

sql:
SELECT candy_id, COUNT(*) AS total_preferences
FROM candy_preferences
GROUP BY candy_id;

external_knowledge:
Less successful chimp = lowest scorer in competitions;
Favorite treat = candy with the highest preference level for the chimp;
Essential details = chimp's ID, name, location, birth date, species, gender, notes, weight, height, health status, dietary restrictions, last checkup date, and caretaker;
Treat specifics = candy ID, name, type, ingredients, supplier, calories, sugar content, and flavor;

sql:
SELECT AVG(score) AS average_first_place_score
FROM competition_participants
WHERE rank = 1;

SELECT chimps.name, chimps.species
FROM chimps
JOIN competition_participants ON chimps.chimp_id = competition_participants.chimp_id;

SELECT chimp_id, name, location_id, health_status, DENSE_RANK() OVER (ORDER BY weight DESC) as weight_rank
FROM chimps
ORDER BY weight_rank;

external_knowledge:
- "sweet tooth" indicates a preference for sweets, particularly candies; 
- "regular basis" corresponds to the frequencies of 'Daily', 'Weekly', or 'Monthly';
- "highest average preference" suggests a query comparing the chimps' average preference levels to the overall average, with a focus on those above the mean.

